mapper.select:
SELECT COUNT(*)
FROM TBL_VOLUN_APPLY
WHERE VOLUN_ACT_NO = #{volunActNo}
  AND USER_NO = #{userNo}
  AND VOLUNACT_APPLYSTATUS = 1

SELECT * FROM ( SELECT ROW_NUMBER() OVER (ORDER BY A.volunActNo DESC) AS RN, A.* FROM ( SELECT VA.Volun_Act_No AS volunActNo, VA.Volun_Act_Title AS volunActTitle, O.ORGAN_NAME AS orgName, VA.Volun_Act_Recru_Begin AS volunActRecruBegin, VA.Volun_Act_Recru_End AS volunActRecruEnd, VA.Volun_Act_Proc_Begin AS volunActProcBegin, VA.Volun_Act_Proc_End AS volunActProcEnd, VA.Volun_Act_Point AS volunActPoint, VA.Volun_Act_Address AS volunActAddress,
CASE WHEN NOW() BETWEEN VA.Volun_Act_Recru_Begin AND DATE_ADD(VA.Volun_Act_Recru_End, INTERVAL 1 DAY) THEN '모집중' WHEN NOW() < VA.Volun_Act_Recru_Begin THEN '모집예정' ELSE '모집마감' END AS recruStatus,
CASE VA.Volun_Act_Act_Type WHEN 1 THEN '환경' WHEN 2 THEN '의료' WHEN 3 THEN '교육' WHEN 4 THEN '생활·편의' WHEN 5 THEN '문화·체육·예술' ELSE '기타' END AS actTypeName,
CASE VA.Volun_Act_Age_Group WHEN 0 THEN '전체' WHEN 1 THEN '청소년' WHEN 2 THEN '청년' WHEN 3 THEN '직장인' END AS ageGroupName
FROM TBL_VOLUN_ACTIVITY VA LEFT JOIN TBL_ORGAN O ON VA.Volun_Act_Organ_No = O.ORGAN_NO
VA.Volun_Act_Act_Type = #{volunActActType}
AND VA.Volun_Act_Age_Group = #{volunActAgeGroup}
AND NOW() BETWEEN VA.Volun_Act_Recru_Begin AND DATE_ADD(VA.Volun_Act_Recru_End, INTERVAL 1 DAY)
AND NOW() < VA.Volun_Act_Recru_Begin
AND NOW() > DATE_ADD(VA.Volun_Act_Recru_End, INTERVAL 1 DAY)
AND O.ORGAN_NAME LIKE CONCAT('%', #{organization}, '%')
AND VA.Volun_Act_Title LIKE CONCAT('%', #{keyword}, '%')
AND VA.Volun_Act_Point = #{keyword}
) A ) B WHERE B.RN > #{startRow} AND B.RN <= #{endRow}

SELECT COUNT(*) FROM TBL_VOLUN_ACTIVITY VA LEFT JOIN TBL_ORGAN O ON VA.Volun_Act_Organ_No = O.ORGAN_NO
VA.Volun_Act_Act_Type = #{volunActActType}
AND VA.Volun_Act_Age_Group = #{volunActAgeGroup}
AND NOW() BETWEEN VA.Volun_Act_Recru_Begin AND DATE_ADD(VA.Volun_Act_Recru_End, INTERVAL 1 DAY)
AND NOW() < VA.Volun_Act_Recru_Begin
AND NOW() > DATE_ADD(VA.Volun_Act_Recru_End, INTERVAL 1 DAY)
AND O.ORGAN_NAME LIKE CONCAT('%', #{organization}, '%')
AND VA.Volun_Act_Title LIKE CONCAT('%', #{keyword}, '%')
AND VA.Volun_Act_Point = #{keyword}

SELECT V.Volun_Act_No AS volunActNo, V.Volun_Act_Title AS volunActTitle, DATE_FORMAT(V.Volun_Act_Recru_Begin, '%Y-%m-%d') AS volunActRecruBegin, DATE_FORMAT(V.Volun_Act_Recru_End, '%Y-%m-%d') AS volunActRecruEnd, DATE_FORMAT(V.Volun_Act_Proc_Begin, '%Y-%m-%d') AS volunActProcBegin, DATE_FORMAT(V.Volun_Act_Proc_End, '%Y-%m-%d') AS volunActProcEnd, V.Volun_Act_Point AS volunActPoint, V.Volun_Act_Begin_Time AS volunActBeginTime, V.Volun_Act_End_Time AS volunActEndTime, V.Volun_Act_Act_Type AS volunActActType, V.Volun_Act_Age_Group AS volunActAgeGroup, V.Volun_Act_Organ_No AS volunActOrganNo, V.Volun_Act_Recru_Max_Count AS volunActRecruMaxCount, V.Volun_Act_Address AS volunActAddress, V.Volun_Act_Address_Detail AS volunActAddressDetail, V.Volun_Act_Detail AS volunActDetail, O.Organ_Name AS orgName,
CASE WHEN NOW() < V.Volun_Act_Recru_Begin THEN '모집예정' WHEN NOW() > DATE_ADD(V.Volun_Act_Recru_End, INTERVAL 1 DAY) THEN '마감' ELSE '모집중' END AS recruStatus
FROM TBL_VOLUN_ACTIVITY V JOIN TBL_ORGAN O ON V.Volun_Act_Organ_No = O.Organ_No WHERE V.Volun_Act_No = #{volunActNo}

mapper.update:
UPDATE TBL_VOLUN_APPLY
SET VOLUNACT_APPLYSTATUS = 0
WHERE VOLUN_ACT_NO = #{volunActNo}
  AND USER_NO = #{userNo}
